import type { VerifyActionArgs } from "./types.js";
import type { VerificationProvidersConfig } from "hardhat/types/config";
import type { HardhatRuntimeEnvironment } from "hardhat/types/hre";
import type { NewTaskActionFunction } from "hardhat/types/tasks";

import { styleText } from "node:util";

import { ensureError } from "@nomicfoundation/hardhat-utils/error";
import { capitalize } from "@nomicfoundation/hardhat-utils/string";

import { verifyContract } from "../../verification.js";
import { resolveConstructorArgs, resolveLibraries } from "../arg-resolution.js";

const verifyAction: NewTaskActionFunction<VerifyActionArgs> = async (
  verifyActionArgs,
  hre,
) => {
  await internalVerifyAction(verifyActionArgs, hre, verifyContract);
};

export async function internalVerifyAction(
  {
    constructorArgs,
    constructorArgsPath,
    librariesPath,
    ...verifyActionArgs
  }: VerifyActionArgs,
  hre: HardhatRuntimeEnvironment,
  verifyContractFn: typeof verifyContract,
): Promise<void> {
  const allProviders: Array<keyof VerificationProvidersConfig> = [
    "etherscan",
    "blockscout",
    "sourcify",
  ];

  const enabledProviders = allProviders.filter(
    (provider) => hre.config.verify[provider].enabled,
  );

  if (enabledProviders.length === 0) {
    console.warn(
      styleText("yellow", "\n⚠️  No verification providers are enabled."),
    );
    process.exitCode = 0;
    return;
  }

  const resolvedConstructorArgs = await resolveConstructorArgs(
    constructorArgs,
    constructorArgsPath,
  );

  const resolvedLibraries = await resolveLibraries(librariesPath);

  let errorOccurred = false;
  for (const provider of enabledProviders) {
    try {
      console.log(
        styleText(["cyan", "bold"], `\n=== ${capitalize(provider)} ===`),
      );
      await verifyContractFn(
        {
          ...verifyActionArgs,
          constructorArgs: resolvedConstructorArgs,
          libraries: resolvedLibraries,
          provider,
        },
        hre,
      );
    } catch (error) {
      ensureError(error);
      // It would be nice to use printErrorMessages
      // from packages/hardhat/src/internal/cli/error-handler.ts
      // for consistent error formatting
      console.error(styleText("red", error.message));
      errorOccurred = true;
    }
  }

  process.exitCode = errorOccurred ? 1 : 0;
}

export default verifyAction;

import { promises as fs } from 'fs';
import path from 'path';
import lockfile from 'proper-lockfile';

import type { HardhatRuntimeEnvironment } from 'hardhat/types/hre';
import {
  ValidationDataCurrent,
  ValidationRunData,
  concatRunData,
  isCurrentValidationData,
} from '@openzeppelin/upgrades-core';

async function lock(file: string) {
  await fs.mkdir(path.dirname(file), { recursive: true });
  return lockfile.lock(file, { retries: { minTimeout: 50, factor: 1.3 }, realpath: false });
}

export async function writeValidations(hre: HardhatRuntimeEnvironment, newRunData: ValidationRunData): Promise<void> {
  const cachePath = getValidationsCachePath(hre);
  let releaseLock;
  try {
    releaseLock = await lock(cachePath);
    const storedData = await readValidations(hre, false).catch(e => {
      // No prior data to append to: either the cache file is absent, or it was
      // outdated and readValidations has already removed it. In both cases,
      // write from scratch.
      if (e instanceof ValidationsCacheNotFound || e instanceof ValidationsCacheOutdated) {
        return undefined;
      } else {
        throw e;
      }
    });
    const validations = concatRunData(newRunData, storedData);
    await fs.writeFile(cachePath, JSON.stringify(validations, null, 2));
  } finally {
    await releaseLock?.();
  }
}

export async function readValidations(
  hre: HardhatRuntimeEnvironment,
  acquireLock = true,
): Promise<ValidationDataCurrent> {
  const cachePath = getValidationsCachePath(hre);
  let releaseLock;
  try {
    if (acquireLock) {
      releaseLock = await lock(cachePath);
    }
    const data = JSON.parse(await fs.readFile(cachePath, 'utf8'));
    if (!isCurrentValidationData(data)) {
      await fs.unlink(cachePath);
      throw new ValidationsCacheOutdated();
    }
    return data;
  } catch (e: any) {
    if (e.code === 'ENOENT') {
      throw new ValidationsCacheNotFound();
    } else {
      throw e;
    }
  } finally {
    await releaseLock?.();
  }
}

export class ValidationsCacheNotFound extends Error {
  constructor() {
    super('Validations cache not found. Recompile with `hardhat compile --force`');
  }
}

export class ValidationsCacheOutdated extends Error {
  constructor() {
    super('Validations cache is outdated. Recompile with `hardhat compile --force`');
  }
}

function getValidationsCachePath(hre: HardhatRuntimeEnvironment): string {
  return path.join(hre.config.paths.cache, 'validations.json');
}

import { analyze } from "@nomicfoundation/solidity-analyzer";
import _ from "lodash";
import { analyzeSolFile } from "../../parser/analyzer/analyzeSolFile";
import { getOrInitialiseSolFileEntry } from "../../utils/getOrInitialiseSolFileEntry";
import { Project } from "../base/Project";

interface DependencyDetail {
  sourceName: string;
  absolutePath: string;
  pragmas: string[];
}

export async function getDependenciesAndPragmas(
  project: Project,
  sourcePath: string,
  sourceName: string = sourcePath,
  visited: Set<string> = new Set() // importName => resolvedPath => bool
): Promise<DependencyDetail[]> {
  const visitedKey = `${sourceName}${sourcePath}`;
  if (visited.has(visitedKey)) {
    return [];
  }
  visited.add(visitedKey);

  let text = project.serverState.solFileIndex[sourcePath]?.text;

  if (text === undefined) {
    // TODO: inject this
    const solFileEntry = getOrInitialiseSolFileEntry(
      project.serverState,
      sourcePath
    );
    if (!solFileEntry.isAnalyzed()) {
      await analyzeSolFile(project.serverState, solFileEntry);
    }
  }

  text = project.serverState.solFileIndex[sourcePath]?.text;

  if (text === undefined) {
    throw new Error(`Couldnt find/index ${sourcePath}`);
  }

  // Analyze current file for import strings and pragmas
  const { imports, versionPragmas } = analyze(text);

  // Build list with current file and prepare for dependencies
  const dependencyDetails = [
    { sourceName, absolutePath: sourcePath, pragmas: versionPragmas },
  ];

  // Recursively crawl dependencies and append. Skip non-existing imports
  const resolvedImports: Array<{
    importName: string;
    resolvedPath: string;
  }> = [];
  for (const importName of imports) {
    const resolvedPath = await project.resolveImportPath(
      sourcePath,
      importName
    );

    if (resolvedPath !== undefined) {
      resolvedImports.push({ importName, resolvedPath });
    }
  }

  for (const resolvedImport of resolvedImports) {
    dependencyDetails.push(
      ...(await getDependenciesAndPragmas(
        project,
        resolvedImport.resolvedPath,
        resolvedImport.importName,
        visited
      ))
    );
  }

  return dependencyDetails;
}

import type { FileManager, KeystoreLoader } from "../types.js";

import { assertHardhatInvariant } from "@nomicfoundation/hardhat-errors";

import { createEmptyEncryptedKeystore } from "../keystores/encryption.js";
import { Keystore } from "../keystores/keystore.js";

export class KeystoreFileLoader implements KeystoreLoader {
  readonly #keystoreFilePath: string;
  readonly #keystoreDevPasswordFilePath: string;
  readonly #fileManager: FileManager;
  #keystoreCache: Keystore | null;

  constructor(
    keystoreFilePath: string,
    keystoreDevPasswordFilePath: string,
    fileManger: FileManager,
  ) {
    this.#keystoreFilePath = keystoreFilePath;
    this.#keystoreDevPasswordFilePath = keystoreDevPasswordFilePath;
    this.#fileManager = fileManger;

    this.#keystoreCache = null;
  }

  public getKeystoreFilePath(): string {
    return this.#keystoreFilePath;
  }

  public getKeystoreDevPasswordFilePath(): string {
    return this.#keystoreDevPasswordFilePath;
  }

  public async isKeystoreInitialized(): Promise<boolean> {
    if (this.#keystoreCache !== null) {
      return true;
    }

    return await this.#fileManager.fileExists(this.#keystoreFilePath);
  }

  public async loadKeystore(): Promise<Keystore> {
    if (this.#keystoreCache !== null) {
      return this.#keystoreCache;
    }

    const keystoreFile = await this.#fileManager.readJsonFile(
      this.#keystoreFilePath,
    );

    const keystore = new Keystore(keystoreFile);
    this.#keystoreCache = keystore;

    return keystore;
  }

  public async createUnsavedKeystore({
    masterKey,
    salt,
  }: {
    masterKey: Uint8Array;
    salt: Uint8Array;
  }): Promise<Keystore> {
    assertHardhatInvariant(
      this.#keystoreCache === null,
      "Cannot create a new Keystore when one is already loaded",
    );

    const keystore = new Keystore(
      createEmptyEncryptedKeystore({ masterKey, salt }),
    );

    this.#keystoreCache = keystore;

    return keystore;
  }

  public async saveKeystoreToFile(): Promise<void> {
    assertHardhatInvariant(
      this.#keystoreCache !== null,
      "Cannot save a keystore that has not been loaded or created",
    );

    const keystoreFile = this.#keystoreCache.toJSON();

    await this.#fileManager.writeJsonFile(this.#keystoreFilePath, keystoreFile);
  }
}

import {
  CodeAction,
  CodeActionKind,
  Diagnostic,
  Range,
} from "vscode-languageserver/node";
import { TextDocument } from "vscode-languageserver-textdocument";
import { attemptConstrainToContractName } from "@compilerDiagnostics/conversions/attemptConstrainToContractName";
import { ResolveActionsContext } from "../types";
import { SolcError, ServerState } from "../../types";
import {
  parseContractDefinition,
  ParseContractDefinitionResult,
} from "./parsing/parseContractDefinition";
import { buildImplementInterfaceQuickFix } from "./common/ImplementInterface/buildImplementInterfaceQuickFix";

export class MarkContractAbstract {
  public code = "3656";
  public blocks = [];

  public fromHardhatCompilerError(
    document: TextDocument,
    error: SolcError
  ): Diagnostic {
    return attemptConstrainToContractName(document, error);
  }

  public resolveActions(
    serverState: ServerState,
    diagnostic: Diagnostic,
    context: ResolveActionsContext
  ): CodeAction[] {
    const parseResult = parseContractDefinition(
      diagnostic,
      context,
      serverState.logger
    );

    if (parseResult === null) {
      return [];
    }

    const implementInterfaceQuickFix = buildImplementInterfaceQuickFix(
      serverState,
      parseResult,
      context
    );

    const addAbstrackQuickFix = this._buildAddAbstractQuickFix(
      parseResult,
      context
    );

    return [implementInterfaceQuickFix, addAbstrackQuickFix].filter(
      (act): act is CodeAction => act !== null
    );
  }

  private _buildAddAbstractQuickFix(
    { tokens, functionSourceLocation }: ParseContractDefinitionResult,
    { document, uri }: ResolveActionsContext
  ): CodeAction | null {
    const contractToken = tokens.find(
      (t) => t.type === "Keyword" && t.value === "contract"
    );

    if (contractToken === undefined || contractToken.range === undefined) {
      return null;
    }

    const startChar =
      functionSourceLocation.start + (contractToken.range?.[0] ?? 0);

    const quickfix = {
      title: `Add abstract to contract declaration`,
      kind: CodeActionKind.QuickFix,
      isPreferred: false,
      edit: {
        changes: {
          [uri]: [
            {
              range: Range.create(
                document.positionAt(startChar),
                document.positionAt(startChar)
              ),
              newText: "abstract ",
            },
          ],
        },
      },
    };

    return quickfix;
  }
}

export interface CompilerInput {
  language: string;
  sources: { [inputSourceName: string]: { content: string } };
  settings: {
    viaIR?: boolean;
    optimizer: {
      runs?: number;
      enabled?: boolean;
      details?: {
        yulDetails: {
          optimizerSteps: string;
        };
      };
    };
    metadata?: { useLiteralContent: boolean };
    outputSelection: {
      [inputSourceName: string]: {
        [contractName: string]: string[];
      };
    };
    evmVersion?: string;
    libraries?: {
      [libraryFileName: string]: {
        [libraryName: string]: string;
      };
    };
    remappings?: string[];
  };
}

export interface CompilerOutputSource {
  id: number;
  ast: any;
}

export interface CompilerOutputSources {
  [inputSourceName: string]: CompilerOutputSource;
}

export interface CompilerOutputBytecode {
  object: string;
  opcodes: string;
  sourceMap: string;
  linkReferences: {
    [sourceName: string]: {
      [libraryName: string]: Array<{ start: number; length: 20 }>;
    };
  };
  immutableReferences?: {
    [key: string]: Array<{ start: number; length: number }>;
  };
}

export interface CompilerOutputContract {
  abi: any;
  evm?: {
    bytecode?: CompilerOutputBytecode;
    deployedBytecode?: CompilerOutputBytecode;
    methodIdentifiers: {
      [methodSignature: string]: string;
    };
  };
}

export interface CompilerOutput {
  errors?: CompilerOutputError[];
  sources: CompilerOutputSources;
  contracts?: {
    [inputSourceName: string]: {
      [contractName: string]: CompilerOutputContract;
    };
  };
}

export interface CompilerOutputError {
  type: string;
  component: string;
  message: string;
  severity: "error" | "warning" | "info";
  errorCode?: string;
  formattedMessage?: string;
}
